import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import ListingCard from '../components/ListingCard';
import { fetchUserProfile } from '../utils';

function UserProfile({ currentUser }) {
  const [profile, setProfile] = useState(null);
  const [error, setError] = useState('');

  useEffect(() => {
    if (!currentUser) {
      setProfile(null);
      setError('');
      return undefined;
    }

    let active = true;

    async function loadProfile() {
      try {
        const data = await fetchUserProfile(currentUser.id);
        if (active) {
          setProfile(data);
        }
      } catch (err) {
        if (active) {
          setError('Unable to load the demo profile. Start the backend on port 5000.');
        }
      }
    }

    loadProfile();
    return () => {
      active = false;
    };
  }, [currentUser]);

  return (
    <main className="page">
      <section className="panel section">
        <span className="eyebrow">Seller profile</span>
        <h2 className="section-title">Profile</h2>
        {!currentUser ? (
          <div className="status error">
            Sign in first to see your profile. <Link to="/auth">Go to login.</Link>
          </div>
        ) : null}
        {error ? <div className="status error">{error}</div> : null}
        {currentUser && !profile ? (
          <p className="muted">Loading profile...</p>
        ) : profile ? (
          <div className="profile-grid">
            <div>
              <h3>{profile.username}</h3>
              <p className="muted">{profile.email}</p>
              <p>{profile.bio || 'No bio provided.'}</p>
              <span className="tag">{profile.campus || 'Campus not set'}</span>
              <div className="profile-details">
                <span className="tag">{profile.school || 'School not set'}</span>
                <span className="tag">{profile.region || 'Region not set'}</span>
                <span className="tag">{profile.area || 'Area not set'}</span>
              </div>
            </div>
            <div>
              <h3>Active listings</h3>
              <div className="cards">
                {profile.listings.length === 0 ? (
                  <div className="empty-state">This seller has no active listings.</div>
                ) : (
                  profile.listings.map((listing) => <ListingCard key={listing.id} listing={listing} />)
                )}
              </div>
            </div>
          </div>
        ) : null}
      </section>
    </main>
  );
}

export default UserProfile;
